package com.example.demo.repository;

import com.example.demo.domain.User;
import com.example.demo.projection.UserAddressProjection;
import org.springframework.data.jpa.repository.JpaRepository;
import org.springframework.data.jpa.repository.Query;

import java.util.Optional;

public interface UserRepository extends JpaRepository<User, Long> {

    boolean existsByUsername(String username);
    boolean existsByEmail(String email);

    @Query("""
        select u
        from User u
        left join fetch u.address a
        where u.id = :userId
    """)
    Optional<User> findDetailById(Long userId);

    @Query("""
        select
            u.username as username,
            u.email as email,
            a.city as city,
            a.country as country
        from User u
        left join u.address a
        where u.id = :userId
    """)
    Optional<UserAddressProjection> findProjectedById(Long userId);
}


