package com.example.demo.service;

import com.example.demo.domain.Address;
import com.example.demo.domain.User;
import com.example.demo.dto.*;
import com.example.demo.exception.ConflictException;
import com.example.demo.exception.ResourceNotFoundException;
import com.example.demo.projection.UserAddressProjection;
import com.example.demo.repository.UserRepository;
import jakarta.transaction.Transactional;
import org.springframework.stereotype.Service;

@Service
@Transactional
public class UserServiceImpl implements UserService {

    private final UserRepository userRepository;

    public UserServiceImpl(UserRepository userRepository) {
        this.userRepository = userRepository;
    }

    @Override
    public UserSummaryResponse createUser(CreateUserRequest request) {
        validateUniqueness(request.getUsername(), request.getEmail());

        User user = new User();
        user.setUsername(request.getUsername());
        user.setEmail(request.getEmail());
        user.setFirstName(request.getFirstName());
        user.setLastName(request.getLastName());
        user.setStatus(request.getStatus());

        User saved = userRepository.save(user);
        return new UserSummaryResponse(saved.getId(), saved.getUsername(), saved.getEmail());
    }

    @Override
    public UserDetailResponse getUserDetail(Long userId) {
        User user = userRepository.findDetailById(userId)
            .orElseThrow(() -> new ResourceNotFoundException("User not found. id=" + userId));
        return mapToDetailResponse(user);
    }

    @Override
    public UserAddressProjection getProjectedUser(Long userId) {
        return userRepository.findProjectedById(userId)
            .orElseThrow(() -> new ResourceNotFoundException("Projected user not found. id=" + userId));
    }

    @Override
    public UserDetailResponse upsertAddress(Long userId, UpsertAddressRequest request) {
        User user = userRepository.findDetailById(userId)
            .orElseThrow(() -> new ResourceNotFoundException("User not found. id=" + userId));

        Address address = user.getAddress();
        if (address == null) {
            address = new Address();
            user.setAddress(address);
        }

        address.setCity(request.getCity());
        address.setStreet(request.getStreet());
        address.setZipCode(request.getZipCode());
        address.setCountry(request.getCountry());

        return mapToDetailResponse(user);
    }

    @Override
    public UserDetailResponse updateUser(Long userId, UpdateUserRequest request) {
        User user = userRepository.findById(userId)
            .orElseThrow(() -> new ResourceNotFoundException("User not found. id=" + userId));

        user.updateBasicInfo(request.getFirstName(), request.getLastName(), request.getStatus());
        return mapToDetailResponse(user);
    }

    @Override
    public void deleteUser(Long userId) {
        User user = userRepository.findById(userId)
            .orElseThrow(() -> new ResourceNotFoundException("User not found. id=" + userId));
        userRepository.delete(user);
    }

    private void validateUniqueness(String username, String email) {
        if (userRepository.existsByUsername(username)) {
            throw new ConflictException("Username already exists: " + username);
        }
        if (userRepository.existsByEmail(email)) {
            throw new ConflictException("Email already exists: " + email);
        }
    }

    private UserDetailResponse mapToDetailResponse(User user) {
        AddressResponse addressResponse = null;
        if (user.getAddress() != null) {
            addressResponse = new AddressResponse(
                user.getAddress().getId(),
                user.getAddress().getCity(),
                user.getAddress().getStreet(),
                user.getAddress().getZipCode(),
                user.getAddress().getCountry(),
                user.getAddress().getCreatedAt()
            );
        }

        return new UserDetailResponse(
            user.getId(),
            user.getUsername(),
            user.getEmail(),
            user.getFirstName(),
            user.getLastName(),
            user.getStatus(),
            user.getVersion(),
            user.getCreatedAt(),
            user.getUpdatedAt(),
            addressResponse
        );
    }
}


